import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
// Components: SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
// Compositions: Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, Modal, Footer, Hero
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
// Interaction wrappers: use as={Clickable} on primitives for onClick, as={Hoverable} for hover, as={Pressable} for press
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
// import { ... } from '@ggui-ai/adapters'; // TODO: adapter integration
// prettier-ignore-end

// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  city: string; // City name
  temperature: number; // Current temperature
  condition: string; // Weather condition (Sunny, Cloudy, Rainy, etc.)
  humidity: number; // Humidity percentage
  windSpeed: number; // Wind speed
  unit: string; // Temperature unit (C or F)
  forecast: Array<{ day?: string; icon?: string; high?: number; low?: number }>; // 5-day forecast array
}

// Helper function to map weather condition strings to emoji icons
function getWeatherIcon(condition: string): string {
  const conditionLower = (condition || '').toLowerCase();
  if (conditionLower.includes('sunny') || conditionLower.includes('clear')) return '☀️';
  if (conditionLower.includes('cloudy') || conditionLower.includes('overcast')) return '☁️';
  if (conditionLower.includes('rainy') || conditionLower.includes('rain')) return '🌧️';
  if (conditionLower.includes('snowy') || conditionLower.includes('snow')) return '❄️';
  if (conditionLower.includes('wind')) return '💨';
  if (conditionLower.includes('storm') || conditionLower.includes('thunder')) return '⛈️';
  if (conditionLower.includes('fog') || conditionLower.includes('mist')) return '🌫️';
  return '🌤️'; // default fallback for unknown conditions
}

function useComponent(props: Props) {
  return {};
}

export default function Component(props: Props) {
  const state = useComponent(props);

  return (
    <Container maxWidth="xl" padding={24}>
      <Stack gap={16}>
        <Stack gap={8}>
          <Heading level={1}>{props.city}</Heading>
          <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">Weather Forecast</Text>
        </Stack>

        {/* CONTENT */}
        <Stack gap={16}>
          {/* Current Weather */}
          <Card shadow="md" padding={24}>
            <Stack gap={16} align="center">
              <Text as={Clickable} style={{ fontSize: '64px', lineHeight: '1' }}>{getWeatherIcon(props.condition)}</Text>
              <Stack gap={4} align="center">
                <Text variant="body" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                  {props.condition}
                </Text>
              </Stack>
              <Heading level={1} align="center">
                {props.temperature}°{props.unit || 'C'}
              </Heading>
            </Stack>
            <Divider margin={16} />
            <Row gap={24} justify="around">
              <Stack gap={4} align="center">
                <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">Humidity</Text>
                <Text variant="body" weight="semibold">{props.humidity}%</Text>
              </Stack>
              <Stack gap={4} align="center">
                <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">Wind Speed</Text>
                <Text variant="body" weight="semibold">{props.windSpeed} {props.windSpeed !== undefined ? 'm/s' : '--'}</Text>
              </Stack>
            </Row>
          </Card>

          {/* 5-Day Forecast */}
          <Stack gap={8}>
            <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">5-Day Forecast</Text>
            <Row gap={8} style={{ overflowX: 'auto', flexWrap: 'nowrap' }}>
               {(props.forecast || []).map((day, idx) => (
                 <Card key={idx} padding={12} shadow="sm" style={{ flex: '1 1 auto', minWidth: '100px' }}>
                   <Stack gap={8} align="center">
                     <Text variant="caption" weight="semibold">
                       {day.day ?? 'N/A'}
                     </Text>
                      <Text style={{ fontSize: '32px', lineHeight: '1' }}>{day.icon || getWeatherIcon('Sunny')}</Text>
                     <Stack gap={2} align="center">
                       <Text variant="bodySmall">
                         <span style={{ fontWeight: 'var(--ggui-font-weight-semibold, 600)' }}>{day.high ?? '--'}°{props.unit || 'C'}</span>
                       </Text>
                       <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                         {day.low ?? '--'}°{props.unit || 'C'}
                       </Text>
                     </Stack>
                   </Stack>
                 </Card>
               ))}
             </Row>
          </Stack>
        </Stack>

        {/* FOOTER / ACTIONS */}
        <Row gap={8} justify="end">
          {/* Actions can be added here */}
        </Row>
      </Stack>
    </Container>
  );
}

