import React, { useState, useCallback, useMemo, useEffect, useRef } from 'react';
// Layout: Container, Card, Stack, Row, Box, Divider, Spacer
// Typography: Text, Heading | Inputs: Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider
// Display: Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip | Data: Table, Tabs, Accordion
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
// Components: SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
// Compositions: Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, Modal, Footer, Hero
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
// Interaction wrappers: use as={Clickable} on primitives for onClick, as={Hoverable} for hover, as={Pressable} for press
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
import { useAction } from '@ggui-ai/wire';
// import { ... } from '@ggui-ai/adapters'; // TODO: adapter integration
// prettier-ignore-end

// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  featureOptions: string[]; // Available feature options for the checkbox step
  satisfactionLabels: string[]; // Labels for satisfaction rating (e.g., Very Unsatisfied to Very Satisfied)
}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called with all collected answers as a structured object */
type ActionSubmitPayload = { name: string; email: string; satisfaction: number; features: string[]; comments: string };





function useComponent(props: Props) {
  // State for the multi-step form
  const [currentStep, setCurrentStep] = useState(1);

  const [formData, setFormData] = useState({
    name: '',
    email: '',
    satisfaction: 0,
    features: [] as string[],
    comments: '',
  });
  const [errors, setErrors] = useState<Record<string, string>>({});

  // Actions — fire-and-forget to agent
  const submit = useAction<ActionSubmitPayload>('submit');

  // Validation helpers
  const validateEmail = useCallback((email: string): boolean => {
    const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
    return emailRegex.test(email);
  }, []);

  const validateStep = useCallback((step: number): boolean => {
    const newErrors: Record<string, string> = {};

    if (step === 1) {
      if (!formData.name.trim()) newErrors.name = 'Name is required';
      if (!formData.email.trim()) newErrors.email = 'Email is required';
      else if (!validateEmail(formData.email)) newErrors.email = 'Please enter a valid email';
    }
    if (step === 2) {
      if (formData.satisfaction === 0) newErrors.satisfaction = 'Please select a rating';
    }
    // Step 3 (features) is optional — no validation needed
    if (step === 4) {
      if (formData.comments.length > 500) newErrors.comments = 'Comments must not exceed 500 characters';
    }

    setErrors(newErrors);
    return Object.keys(newErrors).length === 0;
  }, [formData.name, formData.email, formData.satisfaction, formData.features, formData.comments, validateEmail]);

  // Handlers
  const handleFieldChange = useCallback((field: string, value: unknown) => {
    setFormData((prev) => ({ ...prev, [field]: value }));
    // Clear error for this field when user starts typing
    if (errors[field]) {
      setErrors((prev) => { const next = { ...prev }; delete next[field]; return next; });
    }
  }, [errors]);

  const handleNext = useCallback(() => {
    if (validateStep(currentStep)) {
      if (currentStep < 4) {
        setCurrentStep(currentStep + 1);
      } else if (currentStep === 4) {
        // Move to review (step 4 in user-facing numbering, internal step 5)
        setCurrentStep(5);
      }
    }
  }, [currentStep, validateStep]);

  const handleBack = useCallback(() => {
    if (currentStep > 1) {
      setCurrentStep(currentStep - 1);
    }
  }, [currentStep]);

  const handleSubmit = useCallback(() => {
    submit({
      name: formData.name,
      email: formData.email,
      satisfaction: formData.satisfaction,
      features: formData.features,
      comments: formData.comments,
    });
  }, [formData, submit]);

  const isStep1Valid = useMemo(() => {
    return formData.name.trim() !== '' && formData.email.trim() !== '' && validateEmail(formData.email);
  }, [formData.name, formData.email, validateEmail]);

  const isStep2Valid = useMemo(() => {
    return formData.satisfaction !== 0;
  }, [formData.satisfaction]);

  const isStep3Valid = useMemo(() => {
    return true; // Step 3 is optional
  }, []);

  const isStep4Valid = useMemo(() => {
    return formData.comments.length <= 500;
  }, [formData.comments]);

  const featureOptions = props.featureOptions ?? [];
  const satisfactionLabels = props.satisfactionLabels ?? [];

  return { currentStep, setCurrentStep, formData, handleFieldChange, handleNext, handleBack, handleSubmit, errors, isStep1Valid, isStep2Valid, isStep3Valid, isStep4Valid, featureOptions, satisfactionLabels, submit };
}

export default function Component(props: Props) {
  const state = useComponent(props);

  const stepContent = () => {
    const { currentStep, formData, handleFieldChange, errors } = state;

    if (currentStep === 1) {
      return (
        <Stack gap={16}>
          <Heading level={2}>Tell us about yourself</Heading>
          <Input
            label="Name"
            value={formData.name}
            onChange={(value) => handleFieldChange('name', value)}
            error={errors.name}
            required
          />
          <Input
            label="Email"
            type="email"
            value={formData.email}
            onChange={(value) => handleFieldChange('email', value)}
            error={errors.email}
            required
          />
        </Stack>
      );
    }

    if (currentStep === 2) {
      return (
        <Stack gap={16}>
          <Heading level={2}>How satisfied are you?</Heading>
          <RadioGroup
            label="Satisfaction Rating"
            value={formData.satisfaction.toString()}
            onChange={(value) => handleFieldChange('satisfaction', parseInt(value, 10))}
            options={state.satisfactionLabels.map((label, i) => ({
              value: (i + 1).toString(),
              label,
            }))}
            error={errors.satisfaction}
          />
        </Stack>
      );
    }

    if (currentStep === 3) {
      return (
        <Stack gap={16}>
          <Heading level={2}>Which features interest you?</Heading>
          <Stack gap={8}>
            {state.featureOptions.map((feature) => (
              <Checkbox
                key={feature}
                label={feature}
                checked={formData.features.includes(feature)}
                onChange={(checked) => {
                  const newFeatures = checked
                    ? [...formData.features, feature]
                    : formData.features.filter((f) => f !== feature);
                  handleFieldChange('features', newFeatures);
                }}
              />
            ))}
          </Stack>
          {errors.features && <Alert variant="error">{errors.features}</Alert>}
        </Stack>
      );
    }

    if (currentStep === 4) {
      return (
        <Stack gap={16}>
          <Heading level={2}>Any additional comments?</Heading>
          <TextArea
            label="Comments"
            value={formData.comments}
            onChange={(value) => handleFieldChange('comments', value)}
            maxLength={500}
            showCount
            rows={6}
            error={errors.comments}
          />
        </Stack>
      );
    }

    if (currentStep === 5) {
      const satisfactionLabel = state.satisfactionLabels[formData.satisfaction - 1] || 'Not selected';
      return (
        <Stack gap={16}>
          <Heading level={2}>Review Your Answers</Heading>
          <Card padding={16} shadow="sm">
            <Stack gap={12}>
              <Box>
                <Text variant="label">Name</Text>
                <Text>{formData.name}</Text>
              </Box>
              <Divider />
              <Box>
                <Text variant="label">Email</Text>
                <Text>{formData.email}</Text>
              </Box>
              <Divider />
              <Box>
                <Text variant="label">Satisfaction Rating</Text>
                <Text>{satisfactionLabel}</Text>
              </Box>
              <Divider />
              <Box>
                <Text variant="label">Features of Interest</Text>
                <Text>{formData.features.length > 0 ? formData.features.join(', ') : 'None selected'}</Text>
              </Box>
              <Divider />
              <Box>
                <Text variant="label">Comments</Text>
                <Text>{formData.comments || '(No comments)'}</Text>
              </Box>
            </Stack>
          </Card>
        </Stack>
      );
    }

    return null;
  };

  return (
    <Container maxWidth="xl" padding={24}>
      <Stack gap={16}>
        {/* HEADER */}
        <Stack gap={8}>
          <Heading level={1}>Multi-Step Survey</Heading>
         <Progress value={state.currentStep === 5 ? 4 : state.currentStep} max={4} variant="default" size="md" showLabel={false} />
           <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
             Step {state.currentStep === 5 ? 4 : state.currentStep} of 4
           </Text>
        </Stack>

        {/* CONTENT */}
        <Card padding={24} shadow="md">
          {stepContent()}
        </Card>

        {/* FOOTER / ACTIONS */}
        <Row gap={16} justify="between">
          <Button
            variant="ghost"
            onClick={state.handleBack}
            disabled={state.currentStep === 1}
          >
            Back
          </Button>
          {state.currentStep < 5 && (
            <Button
              variant="primary"
              onClick={state.handleNext}
              disabled={
                (state.currentStep === 1 && !state.isStep1Valid) ||
                (state.currentStep === 2 && !state.isStep2Valid) ||
                (state.currentStep === 3 && !state.isStep3Valid) ||
                (state.currentStep === 4 && !state.isStep4Valid)
              }
            >
              Next
            </Button>
          )}
          {state.currentStep === 5 && (
            <Button variant="primary" onClick={state.handleSubmit}>
              Submit
            </Button>
          )}
        </Row>
      </Stack>
    </Container>
  );
}

// DO NOT EDIT imports — all available components are pre-imported.
// prettier-ignore-start
import React, { useState, useCallback, useMemo, useEffect, useRef } from 'react';
// Layout: Container, Card, Stack, Row, Box, Divider, Spacer
// Typography: Text, Heading | Inputs: Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider
// Display: Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip | Data: Table, Tabs, Accordion
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
// Components: SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
// Compositions: Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, Modal, Footer, Hero
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
// Interaction wrappers: use as={Clickable} on primitives for onClick, as={Hoverable} for hover, as={Pressable} for press
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
import { useAction, useStream } from '@ggui-ai/wire';
// import { ... } from '@ggui-ai/adapters'; // TODO: adapter integration
// prettier-ignore-end

// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  tasks: Array<{ id?: string; title?: string; priority?: 'low' | 'medium' | 'high'; assignee?: string; column?: string; dueDate?: string }>; // Array of tasks with id, title, priority (low/medium/high), assignee initials, column ID, and optional dueDate
  columns: Array<{ id?: string; name?: string }>; // Column definitions: [{id: "todo", name: "To Do"}, {id: "in-progress", name: "In Progress"}, {id: "done", name: "Done"}]
}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called when a task is moved, edited, or created. Payload: { action, taskId, data } */
type ActionTaskUpdatePayload = { action: string; taskId: string; data: { column: string } };


// DO NOT EDIT — stream event types generated from stream contract.
/** Stream event: A task was moved, edited, or created by another user — update it in the board */
type StreamTaskChanged = { action?: 'create' | 'move' | 'edit' | 'delete'; task?: { id?: string; title?: string; priority?: 'low' | 'medium' | 'high'; assignee?: string; column?: string; dueDate?: string } };




function useComponent(props: Props) {
  // State management
  const [tasks, setTasks] = useState(props.tasks || []);
  const [editingTaskId, setEditingTaskId] = useState<string | null>(null);
  const [editingTitle, setEditingTitle] = useState('');
  const [addingToColumn, setAddingToColumn] = useState<string | null>(null);
  const [newTaskTitle, setNewTaskTitle] = useState('');
  const [newTaskPriority, setNewTaskPriority] = useState<'low' | 'medium' | 'high'>('medium');
  const [newTaskAssignee, setNewTaskAssignee] = useState('');
  const [newTaskDueDate, setNewTaskDueDate] = useState('');

  // Actions — fire-and-forget to agent
  const taskUpdate = useAction<ActionTaskUpdatePayload>('taskUpdate');

  // Streams — real-time from agent (.latest, .all)
  const taskChanged = useStream<StreamTaskChanged>('taskChanged');

  // Sync tasks with stream updates
  // Sync tasks with stream updates — skip if locally editing to preserve edits
  useEffect(() => {
    if (taskChanged.latest) {
      const { action, task } = taskChanged.latest;
      if (action === 'delete' && task?.id) {
        setTasks((prev) => prev.filter((t) => t.id !== task.id));
      } else if (action === 'create' && task) {
        // Only add if not already present locally
        setTasks((prev) => prev.some((t) => t.id === task.id) ? prev : [...prev, task]);
      } else if ((action === 'move' || action === 'edit') && task?.id) {
        // Skip merge if this task is currently being edited locally
        if (editingTaskId === task.id) {
          return;
        }
        setTasks((prev) =>
          prev.map((t) => (t.id === task.id ? { ...t, ...task } : t))
        );
      }
    }
  }, [taskChanged.latest, editingTaskId]);

  // Sync tasks with prop updates on initial mount only
  useEffect(() => {
    if (props.tasks && props.tasks.length > 0) {
      setTasks(props.tasks);
    }
  }, []);

  // Get tasks for a column
  const getTasksByColumn = useCallback(
    (columnId: string) => tasks.filter((t) => t.column === columnId),
    [tasks]
  );

  // Count completed tasks
  const completedCount = useMemo(
    () => tasks.filter((t) => t.column === 'done').length,
    [tasks]
  );

  // Total tasks
  const totalCount = tasks.length;

  // Handle task move
  const handleMoveTask = useCallback(
    (taskId: string, newColumn: string) => {
      setTasks((prev) =>
        prev.map((t) => (t.id === taskId ? { ...t, column: newColumn } : t))
      );
      taskUpdate({
        action: 'move',
        taskId,
        data: { column: newColumn },
      });
    },
    [taskUpdate]
  );

  // Handle task edit with full metadata
  const handleEditTask = useCallback(
    (taskId: string, newTitle: string, priority?: 'low' | 'medium' | 'high', assignee?: string, dueDate?: string) => {
      setTasks((prev) => {
        const updated = prev.map((t) =>
          t.id === taskId
            ? { ...t, title: newTitle, priority: priority ?? t.priority, assignee: assignee ?? t.assignee, dueDate: dueDate ?? t.dueDate }
            : t
        );
        const task = updated.find((t) => t.id === taskId);
        taskUpdate({
          action: 'edit',
          taskId,
          data: {
            column: task?.column || 'todo',
            title: newTitle,
            priority: priority ?? task?.priority,
            assignee: assignee ?? task?.assignee,
            dueDate: dueDate ?? task?.dueDate,
          },
        });
        return updated;
      });
      setEditingTaskId(null);
    },
    [taskUpdate]
  );

  // Handle add task with all fields
  // Handle add task with all fields — always add to 'todo' column
  const handleAddTask = useCallback(
    () => {
      if (!newTaskTitle.trim()) return;
      const taskId = `task-${Date.now()}-${Math.random()}`;
      const newTask = {
        id: taskId,
        title: newTaskTitle,
        priority: newTaskPriority,
        assignee: newTaskAssignee || undefined,
        dueDate: newTaskDueDate || undefined,
        column: 'todo',
      };
      setTasks((prev) => [...prev, newTask]);
      taskUpdate({
        action: 'create',
        taskId,
        data: {
          column: 'todo',
          title: newTaskTitle,
          priority: newTaskPriority,
          assignee: newTaskAssignee || undefined,
          dueDate: newTaskDueDate || undefined,
        },
      });
      setNewTaskTitle('');
      setNewTaskPriority('medium');
      setNewTaskAssignee('');
      setNewTaskDueDate('');
      setAddingToColumn(null);
    },
    [newTaskTitle, newTaskPriority, newTaskAssignee, newTaskDueDate, taskUpdate]
  );

  return {
    tasks,
    setTasks,
    editingTaskId,
    setEditingTaskId,
    editingTitle,
    setEditingTitle,
    addingToColumn,
    setAddingToColumn,
    newTaskTitle,
    setNewTaskTitle,
    newTaskPriority,
    setNewTaskPriority,
    newTaskAssignee,
    setNewTaskAssignee,
    newTaskDueDate,
    setNewTaskDueDate,
    taskUpdate,
    taskChanged,
    getTasksByColumn,
    completedCount,
    totalCount,
    handleMoveTask,
    handleEditTask,
    handleAddTask,
  };
}
// Helper to get priority color
const getPriorityColor = (priority?: string): 'primary' | 'warning' | 'error' | 'default' => {
  switch (priority) {
    case 'high':
      return 'error';
    case 'medium':
      return 'warning';
    case 'low':
      return 'primary';
    default:
      return 'default';
  }
};

// Task card component
// Task card component
const TaskCard = ({
  task,
  isEditing,
  editingTitle,
  onEditStart,
  onEditChange,
  onEditSave,
  onEditCancel,
  onMove,
  columns,
  onEditPriority,
  onEditAssignee,
  onEditDueDate,
}: {
  task: { id?: string; title?: string; priority?: 'low' | 'medium' | 'high'; assignee?: string; column?: string; dueDate?: string };
  isEditing: boolean;
  editingTitle: string;
  onEditStart: () => void;
  onEditChange: (value: string) => void;
  onEditSave: () => void;
  onEditCancel: () => void;
  onMove: (columnId: string) => void;
  columns: Array<{ id?: string; name?: string }>;
  onEditPriority?: (priority: 'low' | 'medium' | 'high') => void;
  onEditAssignee?: (assignee: string) => void;
  onEditDueDate?: (dueDate: string) => void;
}) => {
