// Helper component for a single element cell
function ElementCell({ element, isSelected, onClick }: { element: Props['elements'][0]; isSelected: boolean; onClick: () => void }) {
  const getCategoryColor = (category?: string): string => {
    const colors: Record<string, string> = {
      'alkali-metal': 'var(--ggui-color-warning-50, #fffbeb)',
      'alkaline-earth-metal': 'var(--ggui-color-primary-50, #f0f9ff)',
      'transition-metal': 'var(--ggui-color-info-50, #ecfeff)',
      'lanthanide': 'var(--ggui-color-success-50, #f0fdf4)',
      'actinide': 'var(--ggui-color-error-50, #fef2f2)',
      'other-metal': 'var(--ggui-color-neutral-100, #f3f4f6)',
      'nonmetal': 'var(--ggui-color-secondary-50, #f5f3ff)',
      'halogen': 'var(--ggui-color-warning-100, #fef3c7)',
      'noble-gas': 'var(--ggui-color-primary-100, #e0f2fe)',
    };
    return colors[category || 'other-metal'] || 'var(--ggui-color-surface, #ffffff)';
  };

  return (
    <Card
      as={Clickable}
      onClick={onClick}
      padding={12}
      shadow={isSelected ? 'md' : 'sm'}
      border={isSelected}
      radius="md"
      style={{
        backgroundColor: getCategoryColor(element.category),
        cursor: 'pointer',
        minHeight: '100px',
        display: 'flex',
        flexDirection: 'column',
        justifyContent: 'center',
        alignItems: 'center',
        textAlign: 'center',
        opacity: isSelected ? 1 : 0.9,
        border: isSelected ? `2px solid var(--ggui-color-primary-600, #0284c7)` : undefined,
      }}
      hoverStyle={{ opacity: 1, boxShadow: 'var(--ggui-shape-shadow-md, 0 4px 6px -1px rgba(0,0,0,0.1))' }}
    >
      <Text variant="caption" size="xs" color="var(--ggui-color-onSurfaceVariant, #52525b)" align="left" style={{ position: 'absolute', top: 'var(--ggui-spacing-1, 4px)', left: 'var(--ggui-spacing-1, 4px)' }}>
        {element.atomicNumber}
      </Text>
      <Text variant="label" size="2xl" weight="bold" color="var(--ggui-color-onSurface, #18181b)">
        {element.symbol}
      </Text>
    </Card>
  );
}

function useComponent(props: Props) {
  const [searchQuery, setSearchQuery] = useState('');
  const [selectedElement, setSelectedElement] = useState<Props['elements'][0] | null>(null);

  // Filter elements by name or symbol (case-insensitive)
  const filteredElements = useMemo(() => {
    if (!searchQuery) return props.elements;
    const query = searchQuery.toLowerCase();
    return props.elements.filter(
      (el) =>
        (el.name?.toLowerCase().includes(query)) ||
        (el.symbol?.toLowerCase().includes(query))
    );
  }, [searchQuery, props.elements]);

  // Get unique categories for legend
  const categories = useMemo(() => {
    const cats = new Set(props.elements.map((el) => el.category));
    return Array.from(cats).filter(Boolean).sort();
  }, [props.elements]);

  const getCategoryColor = useCallback((category?: string): string => {
    const colors: Record<string, string> = {
      'alkali-metal': 'var(--ggui-color-warning-50, #fffbeb)',
      'alkaline-earth-metal': 'var(--ggui-color-primary-50, #f0f9ff)',
      'transition-metal': 'var(--ggui-color-info-50, #ecfeff)',
      'lanthanide': 'var(--ggui-color-success-50, #f0fdf4)',
      'actinide': 'var(--ggui-color-error-50, #fef2f2)',
      'other-metal': 'var(--ggui-color-neutral-100, #f3f4f6)',
      'nonmetal': 'var(--ggui-color-secondary-50, #f5f3ff)',
      'halogen': 'var(--ggui-color-warning-100, #fef3c7)',
      'noble-gas': 'var(--ggui-color-primary-100, #e0f2fe)',
    };
    return colors[category || 'other-metal'] || 'var(--ggui-color-surface, #ffffff)';
  }, []);

  return {
    searchQuery,
    setSearchQuery,
    selectedElement,
    setSelectedElement,
    filteredElements,
    categories,
    getCategoryColor,
  };
}

