  const [quantity, setQuantity] = useState(1);
  const [activeTab, setActiveTab] = useState('description');
  const stock = props.product.stock ?? 0;
  const maxQuantity = Math.max(1, stock);
  const isOutOfStock = stock <= 0;
  const isLowStock = stock > 0 && stock <= 5;

  const handleQuantityChange = useCallback((value: number) => {
    setQuantity(Math.min(maxQuantity, Math.max(1, value)));
  }, [maxQuantity]);

  const handleAddToCart = useCallback(() => {
    if (!isOutOfStock && props.product.id) {
      addToCart({ productId: props.product.id, quantity });
    }
  }, [addToCart, isOutOfStock, props.product.id, quantity]);

  const renderStars = useCallback((rating: number) => {
    return Array.from({ length: 5 }).map((_, i) => (
      <Icon key={i} name={i < Math.floor(rating) ? 'star' : 'star'} size={16} color={i < Math.floor(rating) ? 'var(--ggui-color-warning-500, #f59e0b)' : 'var(--ggui-color-outline, #d4d4d8)'} />
    ));
  }, []);

  return { quantity, setQuantity, activeTab, setActiveTab, handleQuantityChange, handleAddToCart, stock, isOutOfStock, isLowStock, maxQuantity, renderStars, addToCart };
}

