          </Stack>
        </Stack>

        {/* MIDDLE SECTION: Tabs */}
        <Tabs
          variant="line"
          activeKey={state.activeTab}
          onChange={state.setActiveTab}
          items={[
            {
              key: 'description',
              label: 'Description',
              content: (
                <Stack gap={8} style={{ paddingTop: '16px' }}>
                  <Text variant="body">{product.description || 'No description available'}</Text>
                </Stack>
              ),
            },
            {
              key: 'specifications',
              label: 'Specifications',
              content: (
                <Stack gap={8} style={{ paddingTop: '16px' }}>
                  {Array.isArray(product.specifications) && product.specifications.length > 0 ? (
                    <Table
                      columns={[
                        { key: 'name', header: 'Property', width: '40%' },
                        { key: 'value', header: 'Value', width: '60%' },
                      ]}
                      data={product.specifications.map((spec: any, idx: number) => ({
                        id: idx.toString(),
                        name: typeof spec === 'object' && spec !== null && 'name' in spec ? (spec as any).name : JSON.stringify(spec),
                        value: typeof spec === 'object' && spec !== null && 'value' in spec ? (spec as any).value : JSON.stringify(spec),
                      }))}
                      striped
                    />
                  ) : (
                    <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">No specifications available</Text>
                  )}
                </Stack>
              ),
            },
            {
              key: 'reviews',
              label: 'Reviews',
              content: (
                <Stack gap={12} style={{ paddingTop: '16px' }}>
                  {Array.isArray(product.reviews) && product.reviews.length > 0 ? (
                    product.reviews.map((review: any, idx: number) => (
                      <Card key={idx} padding={16} shadow="sm">
                        <Stack gap={8}>
                          <Stack direction="horizontal" gap={8} align="start" justify="between">
                            <Stack gap={2}>
                              <Text variant="label">{typeof review === 'object' && review !== null && 'author' in review ? (review as any).author : 'Anonymous'}</Text>
                              <Row gap={2}>
                                {state.renderStars(typeof review === 'object' && review !== null && 'rating' in review ? (review as any).rating : 0)}
                              </Row>
                            </Stack>
                            <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">{typeof review === 'object' && review !== null && 'date' in review ? new Date((review as any).date).toLocaleDateString() : 'N/A'}</Text>
                          </Stack>
                          <Text variant="body">{typeof review === 'object' && review !== null && 'text' in review ? (review as any).text : JSON.stringify(review)}</Text>
                        </Stack>
                      </Card>
                    ))
                  ) : (
                    <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">No reviews yet</Text>
                  )}
                </Stack>
              ),
            },
          ]}
        />

         {/* BOTTOM SECTION: Quantity + Add to Cart */}
