           <Stack gap={4} direction="horizontal" align="center">
             <Text variant="label">Quantity:</Text>
             <Button variant="ghost" size="sm" onClick={() => state.handleQuantityChange(state.quantity - 1)} disabled={state.quantity <= 1}>
               −
             </Button>
             <Input
               label="Qty"
               type="number"
               value={state.quantity.toString()}
               onChange={(val) => state.handleQuantityChange(parseInt(val, 10) || 1)}
               style={{ width: '60px', textAlign: 'center' }}
             />
             <Button variant="ghost" size="sm" onClick={() => state.handleQuantityChange(state.quantity + 1)} disabled={state.quantity >= state.maxQuantity}>
               +
             </Button>
           </Stack>
           <Button
             variant="primary"
             size="md"
             onClick={state.handleAddToCart}
             disabled={state.isOutOfStock}
           >
             Add to Cart
           </Button>
         </Stack>
       </Stack>
     </Container>
   );
 }

