import React, { useState, useCallback, useMemo, useEffect, useRef } from 'react';
// Layout: Container, Card, Stack, Row, Box, Divider, Spacer
// Typography: Text, Heading | Inputs: Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider
// Display: Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip | Data: Table, Tabs, Accordion
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
// Components: SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
// Compositions: Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, Modal, Footer, Hero
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
// Interaction wrappers: use as={Clickable} on primitives for onClick, as={Hoverable} for hover, as={Pressable} for press
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
import { useAction, useStream } from '@ggui-ai/wire';
// import { ... } from '@ggui-ai/adapters'; // TODO: adapter integration
// prettier-ignore-end

// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  title: string; // Chat window title
  currentUser: string; // Current user name (for right-aligning own messages)
  participantCount: number; // Number of participants
  messages: Array<{ sender?: string; text?: string; timestamp?: string }>; // Initial messages to display on mount
}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called when user sends a message. Payload: { text, timestamp } */
type ActionSendMessagePayload = { text: string; timestamp: string };


// DO NOT EDIT — stream event types generated from stream contract.
/** Stream event: New message from another participant — append to message list */
type StreamMessage = { sender?: string; text?: string; timestamp?: string };

/** Stream event: Typing indicator — show/hide based on active flag */
type StreamTyping = { sender?: string; active?: boolean };




function useComponent(props: Props) {
  // State
  const [messageList, setMessageList] = useState(props.messages);
  const [inputText, setInputText] = useState('');
  const [typingUsers, setTypingUsers] = useState<Set<string>>(new Set());
  const messagesEndRef = useRef<HTMLDivElement>(null);

  // Actions — fire-and-forget to agent
  const sendMessage = useAction<ActionSendMessagePayload>('sendMessage');

  // Streams — real-time from agent (.latest, .all)
  const message = useStream<StreamMessage>('message');
  const typing = useStream<StreamTyping>('typing');

  // Auto-scroll to bottom when new messages arrive
  useEffect(() => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [messageList]);

  // Append new message from stream
  useEffect(() => {
    if (message.latest) {
      setMessageList((prev) => [...prev, message.latest!]);
    }
  }, [message.latest]);

  // Handle typing indicator
  useEffect(() => {
    if (typing.latest) {
      const { sender, active } = typing.latest;
      if (sender && sender !== props.currentUser) {
        setTypingUsers((prev) => {
          const next = new Set(prev);
          if (active) {
            next.add(sender);
          } else {
            next.delete(sender);
          }
          return next;
        });
      }
    }
  }, [typing.latest, props.currentUser]);

  // Send message handler
  const handleSendMessage = useCallback(() => {
    if (inputText.trim()) {
      sendMessage({ text: inputText, timestamp: new Date().toISOString() });
      setInputText('');
    }
  }, [inputText, sendMessage]);

  return { messageList, inputText, setInputText, handleSendMessage, typingUsers, messagesEndRef };
}

export default function Component(props: Props) {
  const { messageList, inputText, setInputText, handleSendMessage, typingUsers, messagesEndRef } = useComponent(props);

  return (
    <Container maxWidth="2xl" padding={0}>
      <Card shadow="lg" radius="lg" padding={0} style={{ display: 'flex', flexDirection: 'column', height: '100vh' }}>
        {/* HEADER */}
        <Box paddingX={24} paddingY={16} style={{ borderBottom: '1px solid var(--ggui-color-outlineVariant, #e4e4e7)' }}>
          <Stack direction="horizontal" justify="between" align="center">
            <Stack direction="horizontal" align="center" gap={12}>
              <Heading level={3}>{props.title}</Heading>
              <Badge variant="primary" size="sm">{props.participantCount}</Badge>
            </Stack>
            {typingUsers.size > 0 && (
              <Stack direction="horizontal" align="center" gap={6}>
                <Spinner size={16} color="var(--ggui-color-primary-600, #0284c7)" />
                <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                  {Array.from(typingUsers).join(', ')} {typingUsers.size === 1 ? 'is typing' : 'are typing'}...
                </Text>
              </Stack>
            )}
          </Stack>
        </Box>

        {/* MESSAGE LIST */}
        <Stack
          style={{
            flex: 1,
            overflowY: 'auto',
            padding: 'var(--ggui-spacing-4, 16px)',
            backgroundColor: 'var(--ggui-color-surface, #ffffff)',
          }}
          gap={8}
        >
          {messageList.length === 0 ? (
            <Box style={{ display: 'flex', justifyContent: 'center', alignItems: 'center', height: '100%' }}>
              <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                No messages yet. Start the conversation!
              </Text>
            </Box>
          ) : (
            messageList.map((msg, idx) => {
              const isOwnMessage = msg.sender === props.currentUser;
              const showSenderName = !isOwnMessage && (idx === 0 || messageList[idx - 1]?.sender !== msg.sender);
              const timestamp = msg.timestamp ? new Date(msg.timestamp).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' }) : '';

              return (
                <Box
                  key={idx}
                  style={{
                    display: 'flex',
                    justifyContent: isOwnMessage ? 'flex-end' : 'flex-start',
                    marginBottom: 'var(--ggui-spacing-2, 8px)',
                  }}
                >
                  <Box
                    paddingX={12}
                    paddingY={8}
                    borderRadius="8px"
                    style={{
                      backgroundColor: isOwnMessage
                        ? 'var(--ggui-color-primary-600, #0284c7)'
                        : 'var(--ggui-color-surfaceVariant, #f4f4f5)',
                      maxWidth: '60%',
                    }}
                  >
                    {showSenderName && !isOwnMessage && (
                      <Text
                        variant="label"
                        size="xs"
                        color={isOwnMessage ? '#ffffff' : 'var(--ggui-color-onSurface, #18181b)'}
                        style={{ marginBottom: 'var(--ggui-spacing-1, 4px)' }}
                      >
                        {msg.sender}
                      </Text>
                    )}
                    <Text
                      variant="body"
                      color={isOwnMessage ? '#ffffff' : 'var(--ggui-color-onSurface, #18181b)'}
                    >
                      {msg.text}
                    </Text>
                    {timestamp && (
                      <Text
                        variant="caption"
                        color={isOwnMessage ? 'rgba(255,255,255,0.7)' : 'var(--ggui-color-onSurfaceVariant, #52525b)'}
                        style={{ marginTop: 'var(--ggui-spacing-1, 4px)' }}
                      >
                        {timestamp}
                      </Text>
                    )}
                  </Box>
                </Box>
              );
            })
          )}
          <div ref={messagesEndRef} />
        </Stack>

        {/* INPUT AREA */}
        <Box paddingX={16} paddingY={12} style={{ borderTop: '1px solid var(--ggui-color-outlineVariant, #e4e4e7)' }}>
          <Stack direction="horizontal" gap={8} align="center">
            <Input
              label="Message"
              placeholder="Type a message..."
              value={inputText}
              onChange={setInputText}
              onKeyPress={(e: React.KeyboardEvent<HTMLInputElement>) => {
                if (e.key === 'Enter' && !e.shiftKey) {
                  e.preventDefault();
                  handleSendMessage();
                }
              }}
              style={{ flex: 1 }}
            />
            <Button
              variant="primary"
              size="md"
              disabled={!inputText.trim()}
              onClick={handleSendMessage}
            >
              Send
            </Button>
          </Stack>
        </Box>
      </Card>
    </Container>
  );
}

