import React, { useState, useCallback, useMemo, useEffect, useRef } from 'react';
// Layout: Container, Card, Stack, Row, Box, Divider, Spacer
// Typography: Text, Heading | Inputs: Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider
// Display: Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip | Data: Table, Tabs, Accordion
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
// Components: SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
// Compositions: Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, Modal, Footer, Hero
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
// Interaction wrappers: use as={Clickable} on primitives for onClick, as={Hoverable} for hover, as={Pressable} for press
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
import { useStream } from '@ggui-ai/wire';
// import { ... } from '@ggui-ai/adapters'; // TODO: adapter integration
// prettier-ignore-end

// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  stocks: Array<{ symbol?: string; name?: string; price?: number; change?: number; changePercent?: number }>; // Array of stocks with symbol, name, price, change, changePercent
}


// DO NOT EDIT — stream event types generated from stream contract.
/** Stream event: Updated price data for one or more stocks */
type StreamPriceUpdate = { symbol?: string; price?: number; change?: number; changePercent?: number };

/** Stream event: Market open/closed status update */
type StreamMarketStatus = { status?: 'open' | 'closed' | 'pre-market' | 'after-hours'; timestamp?: string };




function useComponent(props: Props) {
  // Merge initial stock data with live updates
  const [stockData, setStockData] = useState<Record<string, any>>(() => {
    const initial: Record<string, any> = {};
    props.stocks?.forEach(stock => {
      if (stock.symbol) {
        initial[stock.symbol] = stock;
      }
    });
    return initial;
  });

  // Track last update timestamp for flash animation
  const [lastUpdated, setLastUpdated] = useState<Record<string, number>>({});
  const [lastUpdateTime, setLastUpdateTime] = useState<Date>(new Date());

  // Streams — real-time from agent (.latest, .all)
  const priceUpdate = useStream<StreamPriceUpdate>('priceUpdate'); // Updated price data for one or more stocks
  const marketStatus = useStream<StreamMarketStatus>('marketStatus'); // Market open/closed status update

  // Merge price updates into stock data
  useEffect(() => {
    if (priceUpdate.latest) {
      const { symbol, price, change, changePercent } = priceUpdate.latest;
      if (symbol) {
        setStockData(prev => ({
          ...prev,
          [symbol]: {
            ...prev[symbol],
            price: price !== undefined ? price : prev[symbol]?.price,
            change: change !== undefined ? change : prev[symbol]?.change,
            changePercent: changePercent !== undefined ? changePercent : prev[symbol]?.changePercent,
          }
        }));
        // Trigger flash animation and update timestamp
        setLastUpdated(prev => ({ ...prev, [symbol]: Date.now() }));
        setLastUpdateTime(new Date());
      }
    }
  }, [priceUpdate.latest]);

  return { stockData, lastUpdated, lastUpdateTime, marketStatus, priceUpdate };
}

function Component(props: Props) {
  const { stockData, lastUpdated, lastUpdateTime, marketStatus } = useComponent(props);

  // Format price with 2 decimals
  const formatPrice = useCallback((price?: number) => {
    if (price === undefined) return '—';
    return `$${price.toFixed(2)}`;
  }, []);

  // Determine if change is positive/negative
  const getChangeColor = useCallback((change?: number) => {
    if (change === undefined) return 'var(--ggui-color-onSurface, #18181b)';
    return change >= 0 ? 'var(--ggui-color-success, #16a34a)' : 'var(--ggui-color-error, #dc2626)';
  }, []);

  // Check if a stock was recently updated for flash animation
  const isFlashing = useCallback((symbol: string) => {
    const updateTime = lastUpdated[symbol];
    if (!updateTime) return false;
    return Date.now() - updateTime < 500; // Flash for 500ms
  }, [lastUpdated]);

  // Get flash opacity (1 initially, fades to 0.5)
  const getFlashOpacity = useCallback((symbol: string) => {
    const updateTime = lastUpdated[symbol];
    if (!updateTime) return 1;
    const elapsed = Date.now() - updateTime;
    if (elapsed > 500) return 1;
    // Fade from 0.3 to 1 over 500ms
    return 0.3 + (elapsed / 500) * 0.7;
  }, [lastUpdated]);

  // Get formatted last updated timestamp — updates on priceUpdate stream
  const lastUpdatedTimestamp = useMemo(() => {
    const hours = lastUpdateTime.getHours().toString().padStart(2, '0');
    const minutes = lastUpdateTime.getMinutes().toString().padStart(2, '0');
    const seconds = lastUpdateTime.getSeconds().toString().padStart(2, '0');
    return `Last Updated: ${hours}:${minutes}:${seconds}`;
  }, [lastUpdateTime]);

  // Sort stocks for consistent display
  const sortedStocks = useMemo(() => {
    return Object.values(stockData).sort((a, b) => {
      const symbolA = a?.symbol || '';
      const symbolB = b?.symbol || '';
      return symbolA.localeCompare(symbolB);
    });
  }, [stockData]);

  return (
    <Container maxWidth="xl" padding={24}>
      <Stack gap={24}>
        {/* HEADER WITH TITLE AND MARKET STATUS */}
        <Stack gap={8}>
          <Stack direction="horizontal" justify="between" align="center">
            <Heading level={1}>Market Watch</Heading>
            {marketStatus.latest && (
              <Badge variant={marketStatus.latest.status === 'open' ? 'success' : 'default'}>{marketStatus.latest.status || 'unknown'}</Badge>
            )}
          </Stack>
          <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
            {lastUpdatedTimestamp}
          </Text>
        </Stack>

        {/* STOCK CARDS GRID */}
        {sortedStocks.length === 0 ? (
          <Alert variant="info">No stocks available. Check your data source.</Alert>
        ) : (
          <CardGrid columns={{ sm: 1, lg: 3 }} gap={16}>
            {sortedStocks.map((stock) => {
              const symbol = stock?.symbol || '?';
              const name = stock?.name || 'Unknown';
              const price = stock?.price;
              const change = stock?.change;
              const changePercent = stock?.changePercent;
              const changeColor = getChangeColor(change);
              const flashing = isFlashing(symbol);
              const isPositive = (change ?? 0) >= 0;

              return (
                <Card
                  key={symbol}
                  padding={16}
                  shadow="md"
                  border={true}
                  as={Hoverable}
                  hoverStyle={{ boxShadow: 'var(--ggui-shape-shadow-lg, 0 10px 15px -3px rgba(0,0,0,0.1))', transform: 'translateY(-2px)' }}
                  style={{
                    borderColor: changeColor,
                    opacity: getFlashOpacity(symbol),
                    background: flashing
                      ? 'var(--ggui-color-primary-50, #f0f9ff)'
                      : 'var(--ggui-color-surface, #ffffff)',
                    transition: 'all 300ms ease-out',
                    cursor: 'pointer'
                  }}
                >
                  <Stack gap={12}>
                    {/* TICKER SYMBOL - LARGE AND BOLD */}
                    <Text
                      variant="label"
                      size="2xl"
                      weight="bold"
                      color="var(--ggui-color-onSurface, #18181b)"
                    >
                      {symbol}
                    </Text>

                    {/* COMPANY NAME */}
                    <Text
                      variant="bodySmall"
                      color="var(--ggui-color-onSurfaceVariant, #52525b)"
                      truncate
                    >
                      {name}
                    </Text>

                    <Divider margin={4} />

                    {/* CURRENT PRICE */}
                    <Stack direction="horizontal" justify="between" align="center">
                      <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                        Price
                      </Text>
                      <Text
                        variant="bodyLarge"
                        weight="semibold"
                        color="var(--ggui-color-onSurface, #18181b)"
                      >
                        {formatPrice(price)}
                      </Text>
                    </Stack>

                    {/* CHANGE AMOUNT AND PERCENTAGE WITH ARROW */}
                    <Stack direction="horizontal" justify="between" align="center">
                      <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                        Change
                      </Text>
                      <Stack direction="horizontal" gap={4} align="center">
                        <Text
                          variant="label"
                          size="sm"
                          weight="semibold"
                          color={changeColor}
                        >
                          {isPositive ? '▲' : '▼'}
                        </Text>
                        <Text
                          variant="bodySmall"
                          weight="semibold"
                          color={changeColor}
                        >
                          {change !== undefined
                            ? `${isPositive ? '+' : ''}${change.toFixed(2)}`
                            : '—'}{' '}
                          ({changePercent !== undefined
                            ? `${isPositive ? '+' : ''}${changePercent.toFixed(2)}%`
                            : '—'}
                          )
                        </Text>
                      </Stack>
                    </Stack>
                  </Stack>
                </Card>
              );
            })}
          </CardGrid>
        )}
      </Stack>
    </Container>
  );
}

export default Component;

