// prettier-ignore-start
import React, { useState, useCallback, useMemo } from 'react';
// Layout: Container, Card, Stack, Row, Box, Divider, Spacer
// Typography: Text, Heading | Inputs: Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider
// Display: Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip | Data: Table, Tabs, Accordion
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
// Components: SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
// Compositions: Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, Modal, Footer, Hero
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
// Interaction wrappers: use as={Clickable} on primitives for onClick, as={Hoverable} for hover, as={Pressable} for press
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
import { useAction } from '@ggui-ai/wire';
// import { ... } from '@ggui-ai/adapters'; // TODO: adapter integration
// prettier-ignore-end

// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  initialProfile: { name?: string; email?: string; avatar?: string; role?: string; emailNotifications?: boolean; theme?: string }; // Pre-filled profile data for editing (all fields optional)
  avatarOptions: string[]; // Available avatar emojis to choose from
  roleOptions: string[]; // Available role options for the dropdown
}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called with all profile data when user completes onboarding */
type ActionCompletePayload = { name: string; email: string; avatar: string; role: string; emailNotifications: boolean; theme: string };





function useComponent(props: Props) {
  // State for the three-step wizard
  const [currentStep, setCurrentStep] = useState(1);
  const [formData, setFormData] = useState({
    name: props.initialProfile.name || '',
    email: props.initialProfile.email || '',
    avatar: props.initialProfile.avatar || (props.avatarOptions[0] || ''),
    role: props.initialProfile.role || (props.roleOptions[0] || ''),
    emailNotifications: props.initialProfile.emailNotifications ?? true,
    theme: props.initialProfile.theme || 'light',
  });

  // Wire hook for completion action
  const complete = useAction<ActionCompletePayload>('onComplete');

  // Validation helpers
  const isValidEmail = (email: string) => {
    const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
    return emailRegex.test(email);
  };

  const isStep1Valid = useMemo(
    () => formData.name.trim().length > 0 && isValidEmail(formData.email),
    [formData.name, formData.email]
  );

  const isStep2Valid = useMemo(
    () => formData.role.trim().length > 0,
    [formData.role]
  );

  // Handlers
  const handleInputChange = useCallback(
    (field: string, value: string) => {
      setFormData((prev) => ({ ...prev, [field]: value }));
    },
    []
  );

  const handleToggleChange = useCallback(
    (field: string, checked: boolean) => {
      setFormData((prev) => ({ ...prev, [field]: checked }));
    },
    []
  );

  const handleNext = useCallback(() => {
    if (currentStep === 1 && !isStep1Valid) return;
    if (currentStep === 2 && !isStep2Valid) return;
    if (currentStep < 3) {
      setCurrentStep((prev) => prev + 1);
    }
  }, [currentStep, isStep1Valid, isStep2Valid]);

  const handleBack = useCallback(() => {
    if (currentStep > 1) {
      setCurrentStep((prev) => prev - 1);
    }
  }, [currentStep]);

  const handleComplete = useCallback(() => {
    complete(formData);
  }, [formData, complete]);

  return {
    currentStep,
    formData,
    isStep1Valid,
    isStep2Valid,
    handleInputChange,
    handleToggleChange,
    handleNext,
    handleBack,
    handleComplete,
  };
}
}

function Component(props: Props) {
  const state = useComponent(props);
  const { currentStep, formData, isStep1Valid, isStep2Valid, handleInputChange, handleToggleChange, handleNext, handleBack, handleComplete } = state;

  const progressPercent = (currentStep / 3) * 100;

  return (
    <Container maxWidth="lg" padding={24}>
      <Stack gap={24} align="center">
        {/* STEP INDICATOR */}
        <Stack gap={8} style={{ width: '100%', maxWidth: '600px' }}>
          <Row justify="between" align="center">
            <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">
              Step {currentStep} of 3
            </Text>
            <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">
              {currentStep === 1 && 'Profile Setup'}
              {currentStep === 2 && 'Preferences'}
              {currentStep === 3 && 'Review & Confirm'}
            </Text>
          </Row>
          <Progress value={progressPercent} max={100} size="md" />
        </Stack>

        {/* CARD CONTAINER */}
        <Card shadow="md" padding={32} radius="lg" style={{ width: '100%', maxWidth: '600px' }}>
          <Stack gap={24}>
            {/* STEP 1: PROFILE SETUP */}
            {currentStep === 1 && (
              <Stack gap={16}>
                <Heading level={2}>Profile Setup</Heading>
                <Input
                  label="Full Name"
                  placeholder="Enter your name"
                  value={formData.name}
                  onChange={(value) => handleInputChange('name', value)}
                  required
                />
                <Input
                  label="Email Address"
                  type="email"
                  placeholder="you@example.com"
                  value={formData.email}
                  onChange={(value) => handleInputChange('email', value)}
                  error={formData.email.length > 0 && !(/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(formData.email)) ? 'Please enter a valid email' : ''}
                  required
                />
                <Stack gap={12}>
                  <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                    Choose Avatar
                  </Text>
                  <Row gap={8} wrap>
                    {props.avatarOptions.map((emoji) => (
                      <Box
                        key={emoji}
                        as={Clickable}
                        onClick={() => handleInputChange('avatar', emoji)}
                        style={{
                          fontSize: '32px',
                          cursor: 'pointer',
                          padding: 'var(--ggui-spacing-2, 8px)',
                          borderRadius: 'var(--ggui-shape-radius-md, 8px)',
                          border: formData.avatar === emoji ? '2px solid var(--ggui-color-primary-600, #0284c7)' : '2px solid transparent',
                          backgroundColor: formData.avatar === emoji ? 'var(--ggui-color-primary-50, #f0f9ff)' : 'transparent',
                          transition: 'all 200ms ease-in-out',
                        }}
                      >
                        {emoji}
                      </Box>
                    ))}
                  </Row>
                </Stack>
              </Stack>
            )}

            {/* STEP 2: PREFERENCES */}
            {currentStep === 2 && (
              <Stack gap={16}>
                <Heading level={2}>Preferences</Heading>
                <Select
                  label="Role"
                  value={formData.role}
                  onChange={(value) => handleInputChange('role', value)}
                  options={props.roleOptions.map((role) => ({ value: role, label: role }))}
                />
                <Toggle
                  label="Email Notifications"
                  checked={formData.emailNotifications}
                  onChange={(checked) => handleToggleChange('emailNotifications', checked)}
                />
                <Toggle
                  label="Theme preference"
                  checked={formData.theme === 'dark'}
                  onChange={(checked) => handleToggleChange('theme', checked ? 'dark' : 'light')}
                />
              </Stack>
            )}

            {/* STEP 3: REVIEW & CONFIRM */}
            {currentStep === 3 && (
              <Stack gap={16}>
                <Heading level={2}>Review & Confirm</Heading>
                <Stack gap={12} style={{ backgroundColor: 'var(--ggui-color-surfaceVariant, #f4f4f5)', padding: 'var(--ggui-spacing-4, 16px)', borderRadius: 'var(--ggui-shape-radius-md, 8px)' }}>
                  <Stack gap={2}>
                    <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                      Name
                    </Text>
                    <Text variant="body">{formData.name}</Text>
                  </Stack>
                  <Divider orientation="horizontal" margin={8} />
                  <Stack gap={2}>
                    <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                      Email
                    </Text>
                    <Text variant="body">{formData.email}</Text>
                  </Stack>
                  <Divider orientation="horizontal" margin={8} />
                  <Stack gap={2}>
                    <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                      Avatar
                    </Text>
                    <Text variant="body" style={{ fontSize: '24px' }}>{formData.avatar}</Text>
                  </Stack>
                  <Divider orientation="horizontal" margin={8} />
                  <Stack gap={2}>
                    <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                      Role
                    </Text>
                    <Text variant="body">{formData.role}</Text>
                  </Stack>
                  <Divider orientation="horizontal" margin={8} />
                  <Stack gap={2}>
                    <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                      Email Notifications
                    </Text>
                    <Text variant="body">{formData.emailNotifications ? 'Enabled' : 'Disabled'}</Text>
                  </Stack>
                  <Divider orientation="horizontal" margin={8} />
                  <Stack gap={2}>
                    <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                      Theme
                    </Text>
                    <Text variant="body">{formData.theme === 'light' ? 'Light' : 'Dark'}</Text>
                  </Stack>
                </Stack>
              </Stack>
            )}

            {/* NAVIGATION BUTTONS */}
            <Row gap={8} justify="between">
              <Button
                variant="secondary"
                onClick={handleBack}
                disabled={currentStep === 1}
              >
                Go Back
              </Button>
              {currentStep < 3 ? (
                <Button
                  variant="primary"
                  onClick={handleNext}
                  disabled={(currentStep === 1 && !isStep1Valid) || (currentStep === 2 && !isStep2Valid)}
                >
                  Next
                </Button>
              ) : (
                <Button
                  variant="primary"
                  onClick={handleComplete}
                >
                  Complete Setup
                </Button>
              )}
            </Row>
          </Stack>
        </Card>
      </Stack>
    </Container>
  );
}

export default Component;
